kernel_src = """
#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLen,
                                int32_t dim)
    {
        totalLen_ = totalLength;
        rowLen_ = rowLen;
        dim_ = dim;
        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        // We need at most rowLen floats for each of: xLocal, maxLocal, expLocal, sumLocal, output
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, rowLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, rowLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 4, rowLen_ * sizeof(float)); // max, exp, sum, log
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || rowLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t numRows = totalLen_ / rowLen_; // assume divisible

        // Grid-stride over rows
        for (uint32_t row = blockIdx; row < numRows; row += blockNum) {
            uint32_t base = row * rowLen_;
            ProcessRow(base);
        }
    }

private:
    __aicore__ inline void ProcessRow(uint32_t base)
    {
        // Copy in the row
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[base], rowLen_);
        inQueueX_.EnQue(xLocal);

        // Dequeue for compute
        xLocal = inQueueX_.DeQue<float>();

        // Allocate temporaries
        AscendC::LocalTensor<float> maxLocal = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> expLocal = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> sumLocal = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> logSumLocal = tmpQueue_.AllocTensor<float>();

        // Step 1: compute max of the row
        AscendC::LocalTensor<float> maxScalar = maxLocal;
        AscendC::ReduceMax(maxScalar, xLocal, rowLen_); // returns scalar in first element
        float maxVal = maxScalar.GetValue(0);

        // Step 2: x - max
        AscendC::Subs(xLocal, xLocal, maxVal, rowLen_);

        // Step 3: exp(x - max)
        AscendC::Exp(expLocal, xLocal, rowLen_);

        // Step 4: sum of exp
        AscendC::ReduceSum(sumLocal, expLocal, rowLen_);
        float sumVal = sumLocal.GetValue(0);

        // Step 5: log(sum)
        AscendC::Logs(logSumLocal, sumVal, 1); // not used as tensor

        // Step 6: y = (x - max) - log(sum)
        AscendC::Subs(xLocal, xLocal, sumVal, rowLen_); // Actually need log(sum), so we use scalar
        // But we computed logSumLocal as scalar? Let's do properly:
        // We'll reuse expLocal for output
        AscendC::Subs(expLocal, xLocal, logSumLocal.GetValue(0), rowLen_);

        // Free temporaries except one for output
        tmpQueue_.FreeTensor(maxLocal);
        tmpQueue_.FreeTensor(sumLocal);
        tmpQueue_.FreeTensor(logSumLocal);
        // expLocal now holds result
        outQueueY_.EnQue<float>(expLocal);
        inQueueX_.FreeTensor(xLocal);

        // Copy out
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[base], yLocal, rowLen_);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 4> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_{0};
    uint32_t rowLen_{0};
    int32_t dim_{1};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.rowLen, tiling_data.dim);
    op.Process();
}
